create or replace function public.assert_staff_actor(   p_actor_id uuid,   p_allowed_roles text[] default null ) returns public.staff_users language plpgsql security definer set search_path = public as $$ declare   v_actor public.staff_users%rowtype; begin   if p_actor_id is null then     raise exception '?ㅽ깭???뺣낫媛 ?놁뒿?덈떎.';   end if;   select * into v_actor   from public.staff_users   where id = p_actor_id     and is_active = true;   if not found then     raise exception '?쒖꽦 ?ㅽ깭?꾨? 李얠쓣 ???놁뒿?덈떎.';   end if;   if v_actor.auth_user_id <> auth.uid() then     raise exception '?ㅽ깭???몄쬆 ?뺣낫媛 ?쇱튂?섏? ?딆뒿?덈떎.';   end if;   if p_allowed_roles is not null and not (v_actor.role = any(p_allowed_roles)) then     raise exception '沅뚰븳???놁뒿?덈떎.';   end if;   return v_actor; end; $$; revoke execute on function public.assert_staff_actor(uuid, text[]) from public, anon, authenticated;
